     1→const express = require('express');
     2→const bcrypt  = require('bcrypt');
     3→const jwt     = require('jsonwebtoken');
     4→const pool    = require('../db');
     5→const authMiddleware = require('../middleware/auth');
     6→
     7→const router = express.Router();
     8→const SECRET = process.env.JWT_SECRET || 'cortexbuild_secret';
     9→
    10→// POST /api/auth/login
    11→router.post('/login', async (req, res) => {
    12→  const { email, password } = req.body;
    13→  if (!email || !password) return res.status(400).json({ message: 'Email and password required' });
    14→
    15→  try {
    16→    const { rows } = await pool.query('SELECT * FROM users WHERE email = $1', [email.toLowerCase()]);
    17→    const user = rows[0];
    18→    if (!user) return res.status(401).json({ message: 'Invalid email or password' });
    19→
    20→    const valid = await bcrypt.compare(password, user.password_hash);
    21→    if (!valid) return res.status(401).json({ message: 'Invalid email or password' });
    22→
    23→    const token = jwt.sign(
    24→      { id: user.id, email: user.email, role: user.role, name: user.name, company: user.company },
    25→      SECRET,
    26→      { expiresIn: '7d' }
    27→    );
    28→
    29→    const { password_hash, ...safeUser } = user;
    30→    res.json({ token, user: safeUser });
    31→  } catch (err) {
    32→    console.error('[auth/login]', err);
    33→    res.status(500).json({ message: 'Server error' });
    34→  }
    35→});
    36→
    37→// GET /api/auth/me
    38→router.get('/me', authMiddleware, async (req, res) => {
    39→  try {
    40→    const { rows } = await pool.query('SELECT id,name,email,role,company,phone,avatar,created_at FROM users WHERE id = $1', [req.user.id]);
    41→    if (!rows[0]) return res.status(404).json({ message: 'User not found' });
    42→    res.json(rows[0]);
    43→  } catch (err) {
    44→    res.status(500).json({ message: 'Server error' });
    45→  }
    46→});
    47→
    48→// PUT /api/auth/profile
    49→router.put('/profile', authMiddleware, async (req, res) => {
    50→  const { name, phone } = req.body;
    51→  try {
    52→    const { rows } = await pool.query(
    53→      'UPDATE users SET name=$1, phone=$2 WHERE id=$3 RETURNING id,name,email,role,company,phone,avatar',
    54→      [name, phone, req.user.id]
    55→    );
    56→    res.json(rows[0]);
    57→  } catch (err) {
    58→    res.status(500).json({ message: 'Server error' });
    59→  }
    60→});
    61→
    62→// PUT /api/auth/password
    63→router.put('/password', authMiddleware, async (req, res) => {
    64→  const { currentPassword, newPassword } = req.body;
    65→  try {
    66→    const { rows } = await pool.query('SELECT * FROM users WHERE id = $1', [req.user.id]);
    67→    const user = rows[0];
    68→    const valid = await bcrypt.compare(currentPassword, user.password_hash);
    69→    if (!valid) return res.status(400).json({ message: 'Current password is incorrect' });
    70→
    71→    const hash = await bcrypt.hash(newPassword, 10);
    72→    await pool.query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.user.id]);
    73→    res.json({ message: 'Password updated successfully' });
    74→  } catch (err) {
    75→    res.status(500).json({ message: 'Server error' });
    76→  }
    77→});
    78→
    79→module.exports = router;
